    char *end = start + strlen(start) - 1;  // 🟡 엣지 케이스
    while (end > start && isspace(*end)) end--;
    *(end + 1) = '\0';

    if (start != str) {
        memmove(str, start, strlen(start) + 1);
    }
}
```

